-- ══════════════════════════════════════════════════════════════════════════════
-- ProVendor · Demo Data — DELETE
-- ══════════════════════════════════════════════════════════════════════════════
-- Purpose  : Remove every row inserted by insert_demo_data.sql.
--            Real production data is NOT affected because this script only
--            targets the fixed demo UUIDs (00000000-0000-0000-0000-00000000XXXX).
-- How to run : Supabase → SQL Editor → paste → Run
-- Order    : Children before parents (FK cascade safety).
-- ══════════════════════════════════════════════════════════════════════════════

BEGIN;

-- ── Demo UUID prefixes for reference ─────────────────────────────────────────
-- Users   : 00000000-0000-0000-0000-0000000000XX  (01–03 clients, 10–11 companies, 20–21 independents, 99 admin)
-- Jobs    : 00000000-0000-0000-0000-0000000001XX  (100–104)
-- Apps    : 00000000-0000-0000-0000-0000000002XX  (200–203)
-- Docs    : 00000000-0000-0000-0000-0000000004XX  (401–408)
-- Chats   : 00000000-0000-0000-0000-0000000005XX  (500–501)
-- Messages: 00000000-0000-0000-0000-0000000006XX  (601–606)
-- Reviews : 00000000-0000-0000-0000-0000000007XX  (700–701)
-- Notifs  : 00000000-0000-0000-0000-0000000008XX  (800–803)
-- ─────────────────────────────────────────────────────────────────────────────

-- 1. NOTIFICATIONS
DELETE FROM notifications WHERE id IN (
  '00000000-0000-0000-0000-000000000800',
  '00000000-0000-0000-0000-000000000801',
  '00000000-0000-0000-0000-000000000802',
  '00000000-0000-0000-0000-000000000803'
);

-- 2. MESSAGES
DELETE FROM messages WHERE id IN (
  '00000000-0000-0000-0000-000000000601',
  '00000000-0000-0000-0000-000000000602',
  '00000000-0000-0000-0000-000000000603',
  '00000000-0000-0000-0000-000000000604',
  '00000000-0000-0000-0000-000000000605',
  '00000000-0000-0000-0000-000000000606'
);

-- 3. CHATS
DELETE FROM chats WHERE id IN (
  '00000000-0000-0000-0000-000000000500',
  '00000000-0000-0000-0000-000000000501'
);

-- 4. REVIEWS
DELETE FROM reviews WHERE id IN (
  '00000000-0000-0000-0000-000000000700',
  '00000000-0000-0000-0000-000000000701'
);

-- 5. JOB APPLICATIONS
DELETE FROM job_applications WHERE id IN (
  '00000000-0000-0000-0000-000000000200',
  '00000000-0000-0000-0000-000000000201',
  '00000000-0000-0000-0000-000000000202',
  '00000000-0000-0000-0000-000000000203'
);

-- 6. JOB REQUESTS
DELETE FROM job_requests WHERE id IN (
  '00000000-0000-0000-0000-000000000100',
  '00000000-0000-0000-0000-000000000101',
  '00000000-0000-0000-0000-000000000102',
  '00000000-0000-0000-0000-000000000103',
  '00000000-0000-0000-0000-000000000104'
);

-- 7. DOCUMENTS
DELETE FROM documents WHERE id IN (
  '00000000-0000-0000-0000-000000000401',
  '00000000-0000-0000-0000-000000000402',
  '00000000-0000-0000-0000-000000000403',
  '00000000-0000-0000-0000-000000000404',
  '00000000-0000-0000-0000-000000000405',
  '00000000-0000-0000-0000-000000000406',
  '00000000-0000-0000-0000-000000000407',
  '00000000-0000-0000-0000-000000000408'
);

-- 8. SERVICE AREAS  (keyed by provider_id — all demo provider IDs)
DELETE FROM service_areas WHERE provider_id IN (
  '00000000-0000-0000-0000-000000000010',
  '00000000-0000-0000-0000-000000000011',
  '00000000-0000-0000-0000-000000000020',
  '00000000-0000-0000-0000-000000000021'
);

-- 9. PROFILE TABLES  (independents, companies, clients)
DELETE FROM independents WHERE user_id IN (
  '00000000-0000-0000-0000-000000000020',
  '00000000-0000-0000-0000-000000000021'
);

DELETE FROM companies WHERE user_id IN (
  '00000000-0000-0000-0000-000000000010',
  '00000000-0000-0000-0000-000000000011'
);

DELETE FROM clients WHERE user_id IN (
  '00000000-0000-0000-0000-000000000001',
  '00000000-0000-0000-0000-000000000002',
  '00000000-0000-0000-0000-000000000003'
);

-- 10. ADMINS table
DELETE FROM admins WHERE id = '00000000-0000-0000-0000-000000000099';

-- 11. PUBLIC.USERS  (bridge table — all demo user IDs)
DELETE FROM public.users WHERE id IN (
  '00000000-0000-0000-0000-000000000001',
  '00000000-0000-0000-0000-000000000002',
  '00000000-0000-0000-0000-000000000003',
  '00000000-0000-0000-0000-000000000010',
  '00000000-0000-0000-0000-000000000011',
  '00000000-0000-0000-0000-000000000020',
  '00000000-0000-0000-0000-000000000021',
  '00000000-0000-0000-0000-000000000099'
);

-- 12. AUTH.IDENTITIES  (email provider rows)
DELETE FROM auth.identities WHERE user_id IN (
  '00000000-0000-0000-0000-000000000001',
  '00000000-0000-0000-0000-000000000002',
  '00000000-0000-0000-0000-000000000003',
  '00000000-0000-0000-0000-000000000010',
  '00000000-0000-0000-0000-000000000011',
  '00000000-0000-0000-0000-000000000020',
  '00000000-0000-0000-0000-000000000021',
  '00000000-0000-0000-0000-000000000099'
);

-- 13. AUTH.USERS  (must be last — everything else FKs here)
DELETE FROM auth.users WHERE id IN (
  '00000000-0000-0000-0000-000000000001',
  '00000000-0000-0000-0000-000000000002',
  '00000000-0000-0000-0000-000000000003',
  '00000000-0000-0000-0000-000000000010',
  '00000000-0000-0000-0000-000000000011',
  '00000000-0000-0000-0000-000000000020',
  '00000000-0000-0000-0000-000000000021',
  '00000000-0000-0000-0000-000000000099'
);

COMMIT;

-- ══════════════════════════════════════════════════════════════════════════════
-- ✅  All demo data removed. Production data is unaffected.
-- ══════════════════════════════════════════════════════════════════════════════
